package evidence

import (
	"errors"
	"fmt"
	"io"
	"os"
)

// ErrOversize is returned by hard-fail readers (e.g. user-supplied prompt
// files, FEAT-022 §8). Callers compare with errors.Is to surface a
// distinct error class to the user.
var ErrOversize = errors.New("evidence: input exceeds cap")

// OversizeError carries the input-source name, observed size, and cap
// for actionable error messages (FEAT-022 Non-Functional / Failure mode
// clarity).
type OversizeError struct {
	Source        string
	ObservedBytes int64
	CapBytes      int
}

func (e *OversizeError) Error() string {
	return fmt.Sprintf("evidence: %s exceeds cap: observed %d bytes, cap %d bytes",
		e.Source, e.ObservedBytes, e.CapBytes)
}

func (e *OversizeError) Unwrap() error { return ErrOversize }

// ReadFileClamped reads up to max+1 bytes from path. If the file fits
// within max it returns (content, false, len(content), nil). If the file
// exceeds max it returns the first max bytes plus truncated=true and
// originalBytes set to the on-disk size (as observed via os.Stat). The
// implementation does not fully load oversize files into memory
// (FEAT-022 Non-Functional / Performance).
func ReadFileClamped(path string, max int) (content []byte, truncated bool, originalBytes int64, err error) {
	if max < 0 {
		return nil, false, 0, fmt.Errorf("evidence: negative cap %d", max)
	}
	// nolint:gosec // path is supplied by callers that have already validated it.
	f, err := os.Open(path)
	if err != nil {
		return nil, false, 0, err
	}
	defer f.Close()

	st, err := f.Stat()
	if err != nil {
		return nil, false, 0, err
	}
	originalBytes = st.Size()

	// Read max+1 bytes so we can detect overflow without loading the whole file.
	buf := make([]byte, max+1)
	n, readErr := io.ReadFull(f, buf)
	if readErr != nil && readErr != io.EOF && readErr != io.ErrUnexpectedEOF {
		return nil, false, originalBytes, readErr
	}

	if n > max {
		return buf[:max], true, originalBytes, nil
	}
	return buf[:n], false, int64(n), nil
}

// ReadFileHardFail reads path and returns *OversizeError (wrapping
// ErrOversize) if the file exceeds max. Used for user-supplied prompt
// files where silent truncation is forbidden (FEAT-022 §8).
func ReadFileHardFail(path string, max int, source string) ([]byte, error) {
	content, truncated, originalBytes, err := ReadFileClamped(path, max)
	if err != nil {
		return nil, err
	}
	if truncated {
		return nil, &OversizeError{
			Source:        source,
			ObservedBytes: originalBytes,
			CapBytes:      max,
		}
	}
	return content, nil
}

package evidence

import "strings"

// EvidenceAssemblySection is the per-section telemetry record produced by
// the evidence-assembly call sites and consumed by Stages C1, C2, and F
// (FEAT-022 §15). The shape is a contract — downstream stages decode this
// without re-deriving field names.
type EvidenceAssemblySection struct {
	Name             string   `json:"name"`
	BytesIncluded    int      `json:"bytes_included"`
	BytesOmitted     int      `json:"bytes_omitted"`
	TruncationReason string   `json:"truncation_reason"`
	SelectedItems    []string `json:"selected_items"`
	OmittedItems     []string `json:"omitted_items"`
}

// SectionInput is one candidate section handed to FitSections, in
// caller-determined priority order (highest priority first).
type SectionInput struct {
	Name    string
	Content string
	// MinFloor, when true, marks this section as part of the minimum
	// evidence floor (FEAT-022 §5 items 1-2). Floor sections are always
	// included; if even the floor exceeds budget FitSections still
	// emits them but reports the overall overflow via the returned
	// TotalBytes vs budget comparison left to the caller.
	MinFloor bool
	// PerSectionCap, if non-zero, additionally clamps this section to
	// at most this many bytes (using ClampOutput) before budgeting.
	PerSectionCap int
}

// FitResult is the outcome of FitSections.
type FitResult struct {
	Included   []SectionInput
	Omitted    []SectionInput
	TotalBytes int
	Sections   []EvidenceAssemblySection
}

// FitSections selects sections to include under a total byte budget,
// in priority order. Floor sections are always included. Non-floor
// sections are added in order while their content fits the remaining
// budget; sections that don't fit are recorded as omitted.
//
// Default behavior is line-based and type-agnostic (FEAT-022 §1):
// when a section's PerSectionCap is non-zero, content is clamped to
// that cap before budgeting. Markdown-aware extraction is handled by
// callers that need it; this primitive does not parse content.
func FitSections(sections []SectionInput, budget int) FitResult {
	if budget < 0 {
		budget = 0
	}
	res := FitResult{
		Sections: make([]EvidenceAssemblySection, 0, len(sections)),
	}
	used := 0

	// First pass: include all floor sections (apply per-section cap).
	for _, s := range sections {
		if !s.MinFloor {
			continue
		}
		content, reason := capContent(s)
		section := EvidenceAssemblySection{
			Name:          s.Name,
			BytesIncluded: len(content),
			BytesOmitted:  len(s.Content) - len(content),
			SelectedItems: []string{s.Name},
		}
		if reason != "" {
			section.TruncationReason = reason
		}
		used += len(content)
		res.Included = append(res.Included, SectionInput{
			Name: s.Name, Content: content, MinFloor: true,
		})
		res.Sections = append(res.Sections, section)
	}

	// Second pass: non-floor in priority order, fit under remaining budget.
	for _, s := range sections {
		if s.MinFloor {
			continue
		}
		content, reason := capContent(s)
		remaining := budget - used
		if len(content) <= remaining {
			used += len(content)
			res.Included = append(res.Included, SectionInput{
				Name: s.Name, Content: content,
			})
			section := EvidenceAssemblySection{
				Name:          s.Name,
				BytesIncluded: len(content),
				BytesOmitted:  len(s.Content) - len(content),
				SelectedItems: []string{s.Name},
			}
			if reason != "" {
				section.TruncationReason = reason
			}
			res.Sections = append(res.Sections, section)
			continue
		}
		// Doesn't fit even at PerSectionCap — try line-trim to fit.
		if remaining > 0 {
			trimmed := trimToLineBudget(content, remaining-len(TruncationMarker))
			if trimmed != "" {
				body := trimmed + TruncationMarker
				used += len(body)
				res.Included = append(res.Included, SectionInput{
					Name: s.Name, Content: body,
				})
				res.Sections = append(res.Sections, EvidenceAssemblySection{
					Name:             s.Name,
					BytesIncluded:    len(body),
					BytesOmitted:     len(s.Content) - len(body),
					TruncationReason: "budget",
					SelectedItems:    []string{s.Name},
				})
				continue
			}
		}
		// No room: omit entirely.
		res.Omitted = append(res.Omitted, s)
		res.Sections = append(res.Sections, EvidenceAssemblySection{
			Name:             s.Name,
			BytesIncluded:    0,
			BytesOmitted:     len(s.Content),
			TruncationReason: "budget",
			OmittedItems:     []string{s.Name},
		})
	}
	res.TotalBytes = used
	return res
}

func capContent(s SectionInput) (string, string) {
	if s.PerSectionCap <= 0 || len(s.Content) <= s.PerSectionCap {
		return s.Content, ""
	}
	clamped, truncated, _ := ClampOutput(s.Content, s.PerSectionCap)
	if truncated {
		return clamped, "per_section_cap"
	}
	return clamped, ""
}

// trimToLineBudget returns the longest prefix of s, ending on a line
// boundary, whose length is at most budget. Returns "" if budget <= 0
// or the first line alone exceeds budget.
func trimToLineBudget(s string, budget int) string {
	if budget <= 0 {
		return ""
	}
	if len(s) <= budget {
		return s
	}
	cut := strings.LastIndexByte(s[:budget], '\n')
	if cut <= 0 {
		return ""
	}
	return s[:cut+1]
}

package evidence

import (
	"strings"
)

// InlineAssembly is the result of AssembleInline.
type InlineAssembly struct {
	Prompt   string
	Sections []EvidenceAssemblySection
	// Overflow is true when, after all trimming, the assembled prompt
	// would still exceed total. Callers (reviewer/grader) MUST NOT
	// dispatch when Overflow is true (FEAT-022 §7) and should emit the
	// appropriate context_overflow outcome class instead.
	Overflow bool
}

// AssembleInline assembles a prompt by joining priority-ordered
// sections under a total byte budget (FEAT-022 §2 inline-with-cap
// strategy). Per-section caps and floor semantics are honored via the
// SectionInput fields. Sections are joined verbatim with a single
// newline separator between non-empty bodies.
func AssembleInline(sections []SectionInput, total int) InlineAssembly {
	fit := FitSections(sections, total)

	var b strings.Builder
	for i, s := range fit.Included {
		if i > 0 {
			b.WriteByte('\n')
		}
		b.WriteString(s.Content)
	}
	out := b.String()

	overflow := len(out) > total
	return InlineAssembly{
		Prompt:   out,
		Sections: fit.Sections,
		Overflow: overflow,
	}
}

