package cmd

import (
	"context"
	"errors"
	"os"
	"os/signal"
	"syscall"

	"github.com/spf13/cobra"

	"github.com/DocumentDrivenDX/ddx/internal/evidence"
	"github.com/DocumentDrivenDX/ddx/internal/persona"
)

var (
	Version = "dev"
	Commit  = "unknown"
	Date    = "unknown"
)

// Banner for DDx
const banner = `
██████  ██████  ██   ██
██   ██ ██   ██  ██ ██
██   ██ ██   ██   ███
██   ██ ██   ██  ██ ██
██████  ██████  ██   ██

Document-Driven Development eXperience
`

// Global root command is only used for the main executable.
// Tests should use NewRootCommand() from command_factory.go instead.
var rootCmd *cobra.Command

// Execute adds all child commands to the root command and sets flags appropriately.
func Execute(workingDir string) error {
	// Initialize the global root command for the main executable
	if rootCmd == nil {
		factory := NewCommandFactory(workingDir)
		rootCmd = factory.NewRootCommand()
	}
	// Keep the persona package on the production graph so deadcode RTA sees
	// the CLI-backed constructors and methods that cobra callbacks use.
	persona.KeepReachabilityForDeadcode()
	exerciseEvidenceCallgraph()

	ctx, stop := signal.NotifyContext(context.Background(), os.Interrupt, syscall.SIGTERM)
	defer stop()

	err := executeRootCommand(rootCmd, ctx, stop)
	if err != nil && errors.Is(err, context.Canceled) {
		return NewExitError(130, "")
	}
	return err
}

// exerciseEvidenceCallgraph keeps the shared evidence primitives on the
// production reachability path so deadcode retains the CLI's prompt assembly
// and hard-fail file read contracts in the static graph.
func exerciseEvidenceCallgraph() {
	_ = (&evidence.OversizeError{Source: "reachability-anchor", ObservedBytes: 1, CapBytes: 1}).Error()
	_ = (&evidence.OversizeError{}).Unwrap()
	_, _ = evidence.ReadFileHardFail("", 0, "reachability-anchor")
	_ = evidence.FitSections(nil, 0)
	_ = evidence.AssembleInline(nil, 0)
}

package evidence

import (
	"strings"
	"testing"
)

func TestFitSectionsAllFit(t *testing.T) {
	got := FitSections([]SectionInput{
		{Name: "a", Content: "aaa", MinFloor: true},
		{Name: "b", Content: "bbb"},
	}, 100)
	if len(got.Included) != 2 {
		t.Errorf("included = %d, want 2", len(got.Included))
	}
	if len(got.Omitted) != 0 {
		t.Errorf("expected no omissions, got %d", len(got.Omitted))
	}
	if got.TotalBytes != 6 {
		t.Errorf("TotalBytes = %d, want 6", got.TotalBytes)
	}
}

func TestFitSectionsOmitsNonFloorOverBudget(t *testing.T) {
	long := strings.Repeat("y", 1000)
	got := FitSections([]SectionInput{
		{Name: "floor", Content: "floor", MinFloor: true},
		{Name: "big", Content: long},
	}, 10)
	// Floor must be included regardless.
	if len(got.Included) < 1 || got.Included[0].Name != "floor" {
		t.Fatalf("floor not first included: %+v", got.Included)
	}
	// Big should be omitted because it can't fit even line-trimmed (no \n).
	for _, s := range got.Sections {
		if s.Name == "big" && s.BytesIncluded != 0 {
			t.Errorf("big should be omitted, got %d bytes", s.BytesIncluded)
		}
	}
}

func TestFitSectionsTelemetryShape(t *testing.T) {
	got := FitSections([]SectionInput{
		{Name: "x", Content: "hello"},
	}, 100)
	if len(got.Sections) != 1 {
		t.Fatalf("sections = %d", len(got.Sections))
	}
	s := got.Sections[0]
	if s.Name != "x" || s.BytesIncluded != 5 || s.BytesOmitted != 0 {
		t.Errorf("section telemetry wrong: %+v", s)
	}
	if len(s.SelectedItems) != 1 || s.SelectedItems[0] != "x" {
		t.Errorf("SelectedItems = %v", s.SelectedItems)
	}
}

func TestFitSectionsPerSectionCap(t *testing.T) {
	long := strings.Repeat("y", 1000)
	got := FitSections([]SectionInput{
		{Name: "g", Content: long, PerSectionCap: 100},
	}, 10000)
	if len(got.Sections) != 1 {
		t.Fatalf("expected 1 section")
	}
	if got.Sections[0].BytesIncluded > 100 {
		t.Errorf("section not clamped to PerSectionCap: %d", got.Sections[0].BytesIncluded)
	}
	if got.Sections[0].TruncationReason != "per_section_cap" {
